-- ملء محتوى عنقود "الشباب والناشئة" (shabab-nashia) — ستة تصنيفات فرعية
-- draft بالكامل: الأساسيات المبسطة (asasiyyat-mubassata)، الأخلاق
-- والصحبة (akhlaq-suhbat-shabab)، الإنترنت والألعاب ووسائل التواصل
-- (internet-tawasul)، الشبهات والشهوات (shubuhat-shahawat)، بناء
-- الشخصية (bina-shakhsiyya)، قصص الأنبياء والسيرة المبسطة
-- (qasas-anbiya-mubassata). كل تصنيف يحصل على درس واحد (lessons +
-- lesson_sections + lesson_citations)، بنفس أسلوب الدفعات السابقة
-- (body + examples)، بلغة مبسطة تناسب جمهور الشباب والناشئة.
-- لتنوع موضوعات هذا العنقود (بخلاف العناقيد السابقة ذات الموضوع
-- الفقهي الواحد) اختير مصدر معتمد مناسب لكل تصنيف على حدة:
-- 1) الأساسيات المبسطة: حديث جبريل عليه السلام (صحيح البخاري ومسلم
--    مباشرة) — النص الأصلي الجامع لأركان الإسلام والإيمان والإحسان.
-- 2) الأخلاق والصحبة: رياض الصالحين للإمام النووي (باب الحث على
--    مجالسة الصالحين ومصادقتهم).
-- 3) الإنترنت والتواصل: صحيح البخاري ومسلم مباشرة (مبدأ التثبت من
--    الأخبار وتحريم الكذب، أصل يُبنى عليه ضبط التعامل مع المعلومات
--    والشائعات على الإنترنت).
-- 4) الشبهات والشهوات: إغاثة اللهفان من مصايد الشيطان لابن القيم
--    الجوزية (المصدر الكلاسيكي الذي فصّل التمييز بين مرض الشبهة
--    ومرض الشهوة وعلاج كل منهما).
-- 5) بناء الشخصية: إحياء علوم الدين لأبي حامد الغزالي (كتاب رياضة
--    النفس وتهذيب الأخلاق).
-- 6) قصص الأنبياء والسيرة المبسطة: قصص الأنبياء لابن كثير.
-- أربع آيات تحقَّقت حرفياً محليًا من artifacts/majalis/public/data/quran
-- عبر numberInSurah: البقرة 285 (أركان الإيمان)، الكهف 28 (الصبر مع
-- الصالحين)، الحجرات 6 (التثبت من الأخبار)، آل عمران 7 (اتباع
-- المتشابه ابتغاء الفتنة)، الأحزاب 21 (الأسوة الحسنة)، يوسف 111
-- (العبرة في قصص الأنبياء). ستة أحاديث استُشهد بها، تحقَّقت عبر
-- WebSearch قبل الإدراج (كلها متفق عليها إلا حديث المؤمن القوي فمسلم
-- منفردًا): حديث جبريل عليه السلام في سؤاله عن الإسلام والإيمان
-- والإحسان (البخاري 50، مسلم 9)، «مثل الجليس الصالح وجليس السوء كحامل
-- المسك ونافخ الكير» عن أبي موسى الأشعري (البخاري 2101، مسلم 2628)،
-- «إياكم والكذب فإن الكذب يهدي إلى الفجور» عن ابن مسعود (البخاري
-- 6094، مسلم 2607)، «إن الحلال بيّن وإن الحرام بيّن وبينهما مشتبهات»
-- عن النعمان بن بشير (البخاري 52، مسلم 1599)، «المؤمن القوي خير وأحب
-- إلى الله من المؤمن الضعيف» عن أبي هريرة (مسلم 2664)، «سبعة يظلهم
-- الله في ظله... وشاب نشأ في عبادة الله» عن أبي هريرة (البخاري 660،
-- مسلم 1031).
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات الستة عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) الأساسيات المبسطة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='1dd26e23-69e0-4490-935d-a9a9155e1d25' AND title='أركان الإسلام والإيمان: الأساس الذي يبدأ منه كل شاب مسلم') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أركان الإسلام والإيمان: الأساس الذي يبدأ منه كل شاب مسلم', 'شرح مبسط لأركان الإسلام الخمسة وأركان الإيمان الستة كما وردت في حديث جبريل عليه السلام', '1dd26e23-69e0-4490-935d-a9a9155e1d25', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'حديث جبريل: خريطة الدين في سؤال وجواب', 'جاء رجل غريب الهيئة إلى مجلس النبي صلى الله عليه وسلم بين أصحابه، فسأله عن الإسلام فقال: "أن تشهد أن لا إله إلا الله وأن محمدًا رسول الله، وتقيم الصلاة، وتؤتي الزكاة، وتصوم رمضان، وتحج البيت إن استطعت إليه سبيلاً" - فهذه هي الأركان الخمسة التي يقوم عليها بنيان كل مسلم. ثم سأله عن الإيمان فقال: "أن تؤمن بالله وملائكته وكتبه ورسله واليوم الآخر، وتؤمن بالقدر خيره وشره" - فهذه أركان الإيمان الستة التي تصنع اعتقاد القلب. ثم سأله عن الإحسان فقال: "أن تعبد الله كأنك تراه، فإن لم تكن تراه فإنه يراك" - وهذه أعلى درجات الدين، أن يستحضر الشاب مراقبة الله له في كل حال. وبعد أن انصرف الرجل، أخبر النبي صلى الله عليه وسلم أصحابه أنه كان جبريل عليه السلام أتاهم يعلمهم دينهم.', 1),
    (v_lesson, 'examples', 'الآية والحديث الأصل في أركان الإيمان', 'قال تعالى: ﴿آمَنَ الرَّسُولُ بِمَا أُنزِلَ إِلَيْهِ مِن رَّبِّهِ وَالْمُؤْمِنُونَ ۚ كُلٌّ آمَنَ بِاللَّهِ وَمَلَائِكَتِهِ وَكُتُبِهِ وَرُسُلِهِ لَا نُفَرِّقُ بَيْنَ أَحَدٍ مِّن رُّسُلِهِ﴾ (البقرة: 285)، جمعت أركان الإيمان بالله وملائكته وكتبه ورسله في آية واحدة، وهي الأصل القرآني الذي فصّله حديث جبريل لاحقًا. فعن عمر بن الخطاب رضي الله عنه في الحديث الطويل المعروف بحديث جبريل عليه السلام، حين سأل جبريل النبي صلى الله عليه وسلم عن الإسلام والإيمان والإحسان (رواه البخاري 50 ومسلم 9)، وفي آخره قال النبي صلى الله عليه وسلم لعمر: "يا عمر، أتدري من السائل؟ قلت: الله ورسوله أعلم. قال: فإنه جبريل أتاكم يعلمكم دينكم". فهذا الحديث هو أجمع نص يضع للشاب المسلم خريطة دينه كاملة في ثلاث درجات متصاعدة: الإسلام، فالإيمان، فالإحسان.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'صحيح البخاري (50) وصحيح مسلم (9) — حديث جبريل عليه السلام', 1);
  END IF;

  -- 2) الأخلاق والصحبة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='7bc8e9f9-6602-4dd1-9757-c9e6368abba5' AND title='أثر الصحبة الصالحة في بناء أخلاق الشاب المسلم') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أثر الصحبة الصالحة في بناء أخلاق الشاب المسلم', 'بيان أهمية اختيار الرفقة الصالحة وأثرها في تشكيل أخلاق الشاب وسلوكه', '7bc8e9f9-6602-4dd1-9757-c9e6368abba5', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'الجليس ينقل إليك ريحه شئت أم أبيت', 'من أعظم ما يشكّل أخلاق الشاب وشخصيته الرفقة التي يختارها، فالإنسان بطبعه يتأثر بمن يجالسه ويقاربه دون أن يشعر، حتى تصير أخلاق جليسه سارية فيه كسريان العدوى. ولهذا خصص الإمام النووي في كتابه "رياض الصالحين" بابًا مستقلاً بعنوان "الحث على مجالسة الصالحين ومصادقتهم"، جمع فيه النصوص التي توجّه المسلم إلى انتقاء رفقته بعناية، لأن الصاحب الصالح يدلّك على الخير ويذكّرك به إذا نسيت ويعينك عليه، بينما صاحب السوء يجرّك إلى المعصية شيئًا فشيئًا حتى يألفها قلبك. وليست العبرة بمن يصادقك حين الرخاء فحسب، بل بمن يقف معك على الحق حين يشتد الأمر، ومن يذكّرك بالله إذا غفلت لا من يزيدك غفلة.', 1),
    (v_lesson, 'examples', 'الصبر مع الصالحين ومثل حامل المسك ونافخ الكير', 'قال تعالى: ﴿وَاصْبِرْ نَفْسَكَ مَعَ الَّذِينَ يَدْعُونَ رَبَّهُم بِالْغَدَاةِ وَالْعَشِيِّ يُرِيدُونَ وَجْهَهُ ۖ وَلَا تَعْدُ عَيْنَاكَ عَنْهُمْ تُرِيدُ زِينَةَ الْحَيَاةِ الدُّنْيَا﴾ (الكهف: 28)، أمرت بالثبات في مجالسة أهل الصلاح ولو كانوا أقل شأنًا في نظر الدنيا، وعدم الالتفات عنهم طلبًا لبريق أهل الدنيا وزينتها. وفي بيان أثر الجليس على صاحبه، عن أبي موسى الأشعري رضي الله عنه أن النبي صلى الله عليه وسلم قال: "مثل الجليس الصالح والجليس السوء كمثل صاحب المسك وكير الحداد؛ لا يعدمك من صاحب المسك إما تشتريه أو تجد ريحه، وكير الحداد يحرق بدنك أو ثوبك، أو تجد منه ريحًا خبيثة" (متفق عليه، رواه البخاري 2101 ومسلم 2628). فهذا المثل النبوي البليغ يوضّح للشاب بصورة محسوسة أن كل رفقة تترك أثرًا، إما طيبًا كرائحة المسك وإما خبيثًا كدخان الكير، ولا وسط بينهما.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'رياض الصالحين — الإمام النووي (باب الحث على مجالسة الصالحين ومصادقتهم)', 1);
  END IF;

  -- 3) الإنترنت والألعاب ووسائل التواصل
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='c994c469-3aa7-4b54-ace9-88d9e752f2e0' AND title='ضوابط شرعية للتعامل مع الإنترنت ووسائل التواصل الاجتماعي') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('ضوابط شرعية للتعامل مع الإنترنت ووسائل التواصل الاجتماعي', 'مبدأ التثبت من الأخبار وتحريم الكذب كأصل ضابط لتعامل الشاب مع المعلومات والشائعات على الإنترنت', 'c994c469-3aa7-4b54-ace9-88d9e752f2e0', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'التثبت قبل النشر وضبط اللسان في الكتابة', 'صار كثير من الشباب اليوم ناقلاً للخبر ومصدرًا له في آن واحد عبر وسائل التواصل، فتضاعفت مسؤوليته الشرعية في التحقق مما ينشره قبل أن ينشره. فالإسلام لم يترك باب الخبر بلا ضابط، بل أمر بالتثبت من كل نبأ يصل إلى الإنسان قبل تصديقه أو نقله، خشية أن يُصيب به من لا يستحق أذى وهو لا يشعر. وينسحب هذا الأصل مباشرة على كل ما يُتداول في الإنترنت من إشاعات ومنشورات لم يتحقق صاحبها من مصدرها، وعلى الأخبار الكاذبة والعناوين المضللة التي يروّجها البعض طلبًا للمشاهدات، فإن الكذب - سواء بالقول المباشر أو بإعادة نشر ما يُعلم كذبه أو يُظن كذبه - محرّم في كل موضع، وأشد خطرًا حين ينتشر بضغطة واحدة إلى آلاف الناس.', 1),
    (v_lesson, 'examples', 'آية التثبت وحديث تحريم الكذب', 'قال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا إِن جَاءَكُمْ فَاسِقٌ بِنَبَإٍ فَتَبَيَّنُوا أَن تُصِيبُوا قَوْمًا بِجَهَالَةٍ فَتُصْبِحُوا عَلَىٰ مَا فَعَلْتُمْ نَادِمِينَ﴾ (الحجرات: 6)، أمرت بالتثبت من كل خبر قبل تصديقه أو البناء عليه، وهي أصل يستوعب واقع الشائعات والأخبار المجهولة المصدر المنتشرة عبر الإنترنت اليوم. وفي بيان خطورة الكذب وعاقبته، عن عبد الله بن مسعود رضي الله عنه أن النبي صلى الله عليه وسلم قال: "إياكم والكذب، فإن الكذب يهدي إلى الفجور، وإن الفجور يهدي إلى النار، وإن الرجل ليكذب حتى يُكتب عند الله كذابًا" (متفق عليه، رواه البخاري 6094 ومسلم 2607). فمن كذب في منشور أو أعاد نشر خبر يعلم كذبه إرضاءً لمتابعيه دخل تحت هذا الوعيد، وهو ما يوجب على كل شاب مسلم ضبط لسانه وقلمه في كل ما ينشره أو يشاركه.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'صحيح البخاري (6094) وصحيح مسلم (2607)', 1);
  END IF;

  -- 4) الشبهات والشهوات
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='2f3cef88-70f5-4505-9bc2-40d41f1c7e63' AND title='التمييز بين الشبهات والشهوات وطريق الوقاية منهما') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('التمييز بين الشبهات والشهوات وطريق الوقاية منهما', 'الفرق بين مرض الشبهة ومرض الشهوة وعلاج كل منهما كما فصّله ابن القيم في إغاثة اللهفان', '2f3cef88-70f5-4505-9bc2-40d41f1c7e63', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'مرض العقل ومرض القلب: علاج مختلف لكل داء', 'قسّم ابن القيم الجوزية في كتابه "إغاثة اللهفان من مصايد الشيطان" أمراض القلب التي يصيد بها الشيطان الشاب إلى نوعين رئيسين: الشبهة والشهوة، وبيّن أن لكل منهما بابًا يُؤتى منه وعلاجًا يخصه. فالشبهة داء يصيب العقل والفكر، مصدرها الجهل أو الشك في أصل من أصول الدين أو حكم من أحكامه، وعلاجها اليقين المبني على العلم الصحيح والرجوع إلى أهل العلم الثقات عند الحيرة، لا الانسياق خلف كل قول غريب يُطرح دون تمحيص. أما الشهوة فداء يصيب الإرادة والرغبة، مصدرها ميل النفس إلى ما تهواه من محرم، وعلاجها الصبر والمجاهدة وقطع أسباب الفتنة قبل الوقوع فيها. ومن لم يميّز بين البابين قد يعالج داء الشهوة بعلاج الشبهة فلا ينفعه، أو العكس، فتبقى العلة قائمة.', 1),
    (v_lesson, 'examples', 'اتباع المتشابه ابتغاء الفتنة وحديث الحلال البيّن والحرام البيّن', 'قال تعالى: ﴿فَأَمَّا الَّذِينَ فِي قُلُوبِهِمْ زَيْغٌ فَيَتَّبِعُونَ مَا تَشَابَهَ مِنْهُ ابْتِغَاءَ الْفِتْنَةِ وَابْتِغَاءَ تَأْوِيلِهِ﴾ (آل عمران: 7)، وصفت من يتتبع المتشابه من النصوص طلبًا للشك والفتنة، وهي أصل قرآني في بيان طريق أهل الشبهات. وفي بيان منزلة الأمور المشتبهة بين الحلال البيّن والحرام البيّن، عن النعمان بن بشير رضي الله عنهما قال: سمعت رسول الله صلى الله عليه وسلم يقول: "إن الحلال بيّن، وإن الحرام بيّن، وبينهما أمور مشتبهات لا يعلمهن كثير من الناس، فمن اتقى الشبهات فقد استبرأ لدينه وعرضه، ومن وقع في الشبهات وقع في الحرام" (متفق عليه، رواه البخاري 52 ومسلم 1599). فهذا الحديث يرسم للشاب منهجًا عمليًا: الابتعاد عن مواطن الشبهة نفسها قبل الوقوع في الحرام، وهو أسلم الطرق للوقاية من كلا الدائين.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'إغاثة اللهفان من مصايد الشيطان — ابن القيم الجوزية', 1);
  END IF;

  -- 5) بناء الشخصية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='b675557c-5084-4d29-abca-32becd418a54' AND title='بناء الشخصية القوية المتزنة في ضوء الهدي النبوي') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('بناء الشخصية القوية المتزنة في ضوء الهدي النبوي', 'أسس بناء شخصية الشاب المسلم القوية في إيمانها وإرادتها كما وجّه إليها الهدي النبوي وعلماء التربية والأخلاق', 'b675557c-5084-4d29-abca-32becd418a54', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'رياضة النفس على معالي الأمور', 'خصص الإمام الغزالي في موسوعته "إحياء علوم الدين" كتابًا مستقلاً بعنوان "رياضة النفس وتهذيب الأخلاق"، أوضح فيه أن الشخصية القوية المتزنة لا تُوهب دفعة واحدة بل تُبنى بالتدريب والمجاهدة المستمرة، كما يُروَّض الجواد شيئًا فشيئًا حتى يستقيم. ومن أبرز ما دعا إليه: قوة العزيمة في طلب معالي الأمور وترك سفاسفها، والصدق مع النفس في محاسبتها، والاعتياد على الصبر عند الشدائد بدل الجزع، والاتكال على الله مع بذل الأسباب لا الاستسلام للعجز. فبناء الشخصية في التصور الإسلامي ليس مجرد ثقة بالنفس مجردة، بل قوة إيمان تصحبها قوة إرادة وبدن وعمل، ينضبط الجميع بميزان الشرع فلا يطغى جانب على آخر.', 1),
    (v_lesson, 'examples', 'الأسوة الحسنة وحديث المؤمن القوي', 'قال تعالى: ﴿لَقَدْ كَانَ لَكُمْ فِي رَسُولِ اللَّهِ أُسْوَةٌ حَسَنَةٌ لِّمَن كَانَ يَرْجُو اللَّهَ وَالْيَوْمَ الْآخِرَ وَذَكَرَ اللَّهَ كَثِيرًا﴾ (الأحزاب: 21)، جعلت شخصية النبي صلى الله عليه وسلم القدوة الكاملة التي يبني عليها الشاب المسلم شخصيته في كل جوانبها. وفي بيان صفة الشخصية المطلوبة، عن أبي هريرة رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: "المؤمن القوي خير وأحب إلى الله من المؤمن الضعيف، وفي كل خير، احرص على ما ينفعك واستعن بالله ولا تعجز" (رواه مسلم 2664). فربط الحديث بين قوة الإيمان والحرص العملي على ما ينفع وعدم الاستسلام للعجز، وهو منهج متكامل لبناء شخصية الشاب: قوة قلب، وحرص على الفعل، وتوكل على الله دون تواكل.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'إحياء علوم الدين — أبو حامد الغزالي (كتاب رياضة النفس وتهذيب الأخلاق)', 1);
  END IF;

  -- 6) قصص الأنبياء والسيرة المبسطة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='26826d69-7e6c-4216-b8d3-a3beefeb9027' AND title='العبرة من قصص الأنبياء وأثرها في تثبيت الشباب على الحق') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('العبرة من قصص الأنبياء وأثرها في تثبيت الشباب على الحق', 'كيف تبني قصص الأنبياء ثبات الشاب المسلم على دينه وتقدّم له نماذج عملية يقتدي بها', '26826d69-7e6c-4216-b8d3-a3beefeb9027', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'القصة القرآنية منهج تربوي لا سرد تاريخي', 'جمع الإمام ابن كثير في كتابه "قصص الأنبياء" أخبار الأنبياء عليهم السلام من مصادرها الصحيحة، مبينًا أن القرآن الكريم لم يسق قصصهم للتسلية أو مجرد التأريخ، بل لتثبيت قلوب المؤمنين وتقديم نماذج حية يتأسى بها كل جيل، ومنهم الشباب بخاصة في مرحلة تكوّن هويتهم وقناعاتهم. ففي قصة إبراهيم عليه السلام مواجهة الباطل وحده وهو شاب في قومه، وفي قصة يوسف عليه السلام مقاومة الفتنة والصبر على الغربة، وفي قصة موسى عليه السلام الثبات أمام الطغيان والصبر على طول الطريق. هذه القصص ليست أخبارًا بعيدة عن واقع الشاب اليوم، بل مرآة يرى فيها نفسه وتحدياته، ويستمد منها العزيمة على الثبات حين يواجه ما يشبه ما واجهه أولئك الأنبياء الكرام من فتن وضغوط.', 1),
    (v_lesson, 'examples', 'العبرة في القصص وحديث الشاب الذي نشأ في عبادة الله', 'قال تعالى: ﴿لَقَدْ كَانَ فِي قَصَصِهِمْ عِبْرَةٌ لِّأُولِي الْأَلْبَابِ ۗ مَا كَانَ حَدِيثًا يُفْتَرَىٰ وَلَٰكِن تَصْدِيقَ الَّذِي بَيْنَ يَدَيْهِ وَتَفْصِيلَ كُلِّ شَيْءٍ وَهُدًى وَرَحْمَةً لِّقَوْمٍ يُؤْمِنُونَ﴾ (يوسف: 111)، صرّحت بأن الغاية من سياق القصص القرآني هي العبرة لأصحاب العقول لا مجرد الحكاية. وفي بيان مكانة الشاب المستقيم على طاعة الله خاصة، عن أبي هريرة رضي الله عنه أن النبي صلى الله عليه وسلم قال: "سبعة يظلهم الله في ظله يوم لا ظل إلا ظله: الإمام العادل، وشاب نشأ في عبادة الله..." (متفق عليه، رواه البخاري 660 ومسلم 1031). فخصّ الحديث الشاب الناشئ على الطاعة بمنزلة عالية بين السبعة المذكورين، وهي بشارة نبوية مباشرة لكل شاب يثبت على دينه في زمن الفتن، مقتديًا بمواقف الأنبياء الثابتة التي حفظها القرآن.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'قصص الأنبياء — ابن كثير', 1);
  END IF;

